sp_widget.client_script:
function($scope, $location) {
    var c = this;

    c.navigateTo = function(path) {
        $location.path(path);
    };

    c.orderService = function(itemId) {
        $location.path('/sc_cat_item').search({sys_id: itemId});
    };
}

sp_widget.css:
.developer-dashboard {
    padding: var(--carbon-spacing-05);
}

.dashboard-header {
    margin-bottom: var(--carbon-spacing-06);
}

.dashboard-header h1 {
    color: var(--carbon-text-01);
    font-size: 2rem;
    margin-bottom: var(--carbon-spacing-03);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.dashboard-grid {
    display: grid;
    grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
    gap: var(--carbon-spacing-05);
    margin-bottom: var(--carbon-spacing-06);
}

.dashboard-card {
    background: var(--carbon-ui-01);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    padding: var(--carbon-spacing-05);
}

.dashboard-card h2 {
    color: var(--carbon-text-01);
    font-size: 1.25rem;
    margin-bottom: var(--carbon-spacing-04);
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
}

.quick-links {
    display: flex;
    flex-direction: column;
    gap: var(--carbon-spacing-03);
}

.quick-link {
    display: flex;
    align-items: center;
    gap: var(--carbon-spacing-03);
    padding: var(--carbon-spacing-03);
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.2s ease;
    text-decoration: none;
    color: var(--carbon-text-01);
}

.quick-link:hover {
    border-color: var(--carbon-interactive-01);
    background: var(--carbon-hover-ui);
}

.service-list {
    display: flex;
    flex-direction: column;
    gap: var(--carbon-spacing-03);
}

.service-item {
    padding: var(--carbon-spacing-03);
    background: var(--carbon-ui-background);
    border: 1px solid var(--carbon-ui-03);
    border-radius: 4px;
    cursor: pointer;
    transition: all 0.2s ease;
}

.service-item:hover {
    border-color: var(--carbon-interactive-01);
}

.service-item h3 {
    color: var(--carbon-text-01);
    font-size: 0.875rem;
    margin-bottom: var(--carbon-spacing-02);
}

.service-item p {
    color: var(--carbon-text-02);
    font-size: 0.75rem;
}

sp_widget.script:
(function() {
    data.user = gs.getUser();
    data.userName = data.user.getDisplayName();

    // Get relevant catalog items for developers
    data.services = [];
    var gr = new GlideRecord('sc_cat_item');
    gr.addQuery('sc_catalogs', 'c1c1c1c1c1c1c1c1c1c1c1c1c1c1c1c1');
    gr.addQuery('active', true);
    gr.orderBy('order');
    gr.setLimit(5);
    gr.query();

    while (gr.next()) {
        data.services.push({
            sys_id: gr.getValue('sys_id'),
            name: gr.getValue('name'),
            short_description: gr.getValue('short_description')
        });
    }

    // Get user's recent requests
    data.recentRequests = [];
    var reqGr = new GlideRecord('sc_request');
    reqGr.addQuery('requested_for', gs.getUserID());
    reqGr.orderByDesc('sys_created_on');
    reqGr.setLimit(5);
    reqGr.query();

    while (reqGr.next()) {
        data.recentRequests.push({
            number: reqGr.getValue('number'),
            short_description: reqGr.getValue('short_description'),
            state: reqGr.getDisplayValue('request_state')
        });
    }
})();
